 1	import * as React from 'react';
 2	
 3	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
 4	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getAllowedResourceData } from '@kubevirt-utils/resources/shared';
 7	import { K8sResourceCommon, useK8sWatchResources } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Card, CardHeader, CardTitle, Grid, GridItem } from '@patternfly/react-core';
 9	
10	import { useWatchedResourcesHook } from './hooks/useWatchedResourcesInventoryCard';
11	import ResourcesSection from './utils/ResourcesSection';
12	import VMStatusSection from './utils/vm-status-section/VMStatusSection';
13	
14	import './InventoryCard.scss';
15	
16	const InventoryCard: React.FC = () => {
17	  const { t } = useKubevirtTranslation();
18	  const isAdmin = useIsAdmin();
19	
20	  const useWatchedResourcesInventoryCard = useWatchedResourcesHook(isAdmin);
21	  const watchedResources = useWatchedResourcesInventoryCard();
22	
23	  const resources = useK8sWatchResources<{ [key: string]: K8sResourceCommon[] }>(watchedResources);
24	
25	  const vms = isAdmin ? resources?.vms : getAllowedResourceData(resources, VirtualMachineModel);
26	
27	  return (
28	    <Card data-test-id="kv-running-inventory-card">
29	      <CardHeader>
30	        <CardTitle>{t('Inventory')}</CardTitle>
31	      </CardHeader>
32	      <div className="kv-inventory-card__body">
33	        <Grid>
34	          <GridItem span={4}>
35	            <div className="kv-inventory-card__item kv-inventory-card__section-header">
36	              <div className="kv-inventory-card__item-section kv-inventory-card__item--border-right">
37	                <span className="kv-inventory-card__item-text">{t('Resources')}</span>
38	              </div>
39	            </div>
40	          </GridItem>
41	          <GridItem span={8}>
42	            <div className="kv-inventory-card__item kv-inventory-card__section-header">
43	              <div className="kv-inventory-card__item-section">
44	                <span className="kv-inventory-card__item-text">
45	                  {t('VirtualMachines statuses')}
46	                </span>
47	              </div>
48	            </div>
49	          </GridItem>
50	          <GridItem span={4}>
51	            <div className="kv-inventory-card__item">
52	              <div className="kv-inventory-card__item-section kv-inventory-card__item--border-right">
53	                <span className="kv-inventory-card__item-text">
54	                  <ResourcesSection isAdmin={isAdmin} resources={resources} />
55	                </span>
56	              </div>
57	            </div>
58	          </GridItem>
59	          <GridItem span={8}>
60	            <VMStatusSection vms={vms?.data || []} vmsLoaded={vms?.loaded} />
61	          </GridItem>
62	        </Grid>
63	      </div>
64	    </Card>
65	  );
66	};
67	
68	export default InventoryCard;

